//! `phoenix.lock` — the resolved-dependency lockfile.
//!
//! The lockfile pins every **git** dependency to a resolved commit SHA so a
//! clean checkout rebuilds the exact same dependency set. Local `path`
//! dependencies are deliberately **not** recorded: they resolve in place each
//! build and are never SHA-pinned (a locked Phase 3.1 decision — see
//! `docs/design-decisions.md` §Phase 3.1).
//!
//! Format: TOML with one name-keyed table per resolved package.
//!
//! ```toml
//! # Auto-generated by Phoenix. Do not edit by hand.
//! version = 1
//!
//! [packages.http]
//! version = "1.2.3"
//! git = "https://github.com/example/http.git"
//! rev = "9f8e7d6c5b4a39281706f5e4d3c2b1a009876543"
//! ```
//!
//! A present lockfile is authoritative (reproducible builds); `--locked` turns
//! any disagreement between the manifest's resolved graph and the on-disk lock
//! into an error instead of silently rewriting it.

use std::collections::BTreeMap;
use std::path::{Path, PathBuf};

use serde::{Deserialize, Serialize};

use super::graph::{PackageSource, ResolvedGraph};
use crate::manifest::GitRef;

/// The current lockfile schema version. Bumped only on a breaking format change.
pub const LOCKFILE_VERSION: u32 = 1;

/// The header prepended to every generated `phoenix.lock`.
const LOCKFILE_HEADER: &str = "# Auto-generated by Phoenix. Do not edit by hand.\n\
                               # This file pins git dependencies to exact commits for reproducible builds.\n";

/// A parsed/serializable `phoenix.lock`.
#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
pub struct Lockfile {
    /// Lockfile schema version.
    pub version: u32,
    /// Resolved git packages, keyed by dependency name.
    #[serde(default)]
    pub packages: BTreeMap<String, LockedPackage>,
}

/// One locked dependency, tagged by **source kind** so the lockfile entry's
/// origin is explicit rather than inferred. Today only [`LockedPackage::Git`]
/// exists; a future `Registry { name, version, checksum }` variant is purely
/// additive (the registry-readiness seam — see `docs/design-decisions.md`
/// §Phase 3.1 A). The enum is `#[serde(untagged)]`, so the `Git` variant
/// serializes to exactly the established format (no discriminator field) and a
/// registry entry will be told apart by its own fields.
///
/// Two consequences of `untagged` to keep in mind. First, deserialization
/// matches purely by field *shape*, first variant that fits wins — so any future
/// variant (e.g. `Registry`) MUST be structurally disjoint from `Git` (a
/// `git` + `rev` table is unambiguously git), or an entry could deserialize as
/// the wrong source. Second, a malformed entry yields the generic serde error "data
/// did not match any variant of untagged enum LockedPackage" rather than a
/// precise "missing field `rev`"; that diagnostic precision is deliberately
/// traded for the discriminator-free on-disk format.
///
/// For the git variant: `rev` is the resolved commit; `tag`/`branch`/`rev_req`
/// record the *requested* ref so a manifest ref change is detected as drift (a
/// tag request sets `tag`, a branch request `branch`, an explicit `rev` request
/// `rev_req`, a default-branch request none). Recording `rev_req` distinguishes
/// an explicit commit pin from a default-branch pin — both otherwise carry no
/// tag/branch — so a switch between them re-resolves rather than reusing the
/// stale commit. `rev_req` is stored lowercased: git object ids are
/// case-insensitive hex, so canonicalizing keeps a pure-case manifest change
/// from reading as drift in [`Lockfile::diff`].
#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
#[serde(untagged)]
pub enum LockedPackage {
    /// A git-sourced dependency pinned to a resolved commit.
    Git {
        /// The resolved `[package].version`.
        version: String,
        /// The git clone URL.
        git: String,
        /// The requested tag, if the manifest pinned one.
        #[serde(default, skip_serializing_if = "Option::is_none")]
        tag: Option<String>,
        /// The requested branch, if the manifest pinned one.
        #[serde(default, skip_serializing_if = "Option::is_none")]
        branch: Option<String>,
        /// The requested commit (lowercased, possibly abbreviated), if the
        /// manifest pinned an explicit `rev`. Distinguishes a commit pin from a
        /// default-branch pin.
        #[serde(default, skip_serializing_if = "Option::is_none")]
        rev_req: Option<String>,
        /// The resolved commit SHA.
        rev: String,
    },
}

impl LockedPackage {
    /// The resolved `[package].version`.
    pub fn version(&self) -> &str {
        match self {
            LockedPackage::Git { version, .. } => version,
        }
    }

    /// The git clone URL, for a git-sourced entry.
    pub fn git(&self) -> Option<&str> {
        match self {
            LockedPackage::Git { git, .. } => Some(git),
        }
    }

    /// The resolved commit SHA, for a git-sourced entry.
    pub fn rev(&self) -> &str {
        match self {
            LockedPackage::Git { rev, .. } => rev,
        }
    }

    /// The requested tag, if a git entry pinned one.
    pub fn tag(&self) -> Option<&str> {
        match self {
            LockedPackage::Git { tag, .. } => tag.as_deref(),
        }
    }

    /// The requested commit (`rev`-pinned entries only), if any.
    pub fn rev_req(&self) -> Option<&str> {
        match self {
            LockedPackage::Git { rev_req, .. } => rev_req.as_deref(),
        }
    }

    /// Whether `reference` (the manifest's current request) still matches what
    /// this lock entry recorded — the condition for reusing the pinned commit
    /// without re-resolving.
    ///
    /// A `rev` request matches a commit-pinned entry (`rev_req` recorded) whose
    /// resolved commit starts with the requested (possibly abbreviated) SHA. A
    /// default-branch request matches an entry that recorded *no* tag/branch/rev
    /// — reusing the pinned commit is the whole point of locking a moving ref;
    /// only a *change* of ref re-resolves. The two no-tag/no-branch cases are
    /// kept distinct by `rev_req`, so switching a manifest between an explicit
    /// `rev` pin and the default branch re-resolves instead of reusing the
    /// stale commit.
    pub fn matches_ref(&self, reference: &GitRef) -> bool {
        let LockedPackage::Git {
            tag,
            branch,
            rev_req,
            rev,
            ..
        } = self;
        match reference {
            GitRef::Tag(t) => tag.as_deref() == Some(t.as_str()),
            GitRef::Branch(b) => branch.as_deref() == Some(b.as_str()),
            GitRef::Rev(r) => {
                tag.is_none()
                    && branch.is_none()
                    && rev_req.is_some()
                    // Resolved SHAs are lowercase hex; a manifest may pin an
                    // upper/mixed-case (possibly abbreviated) rev, so compare
                    // the prefix case-insensitively rather than re-resolving on
                    // a mere case difference.
                    && starts_with_ignore_ascii_case(rev, r)
            }
            GitRef::DefaultBranch => tag.is_none() && branch.is_none() && rev_req.is_none(),
        }
    }
}

/// Write `contents` to `path` atomically via a sibling temp file + rename.
///
/// The temp name carries the process id so two *different* processes writing
/// the same lockfile don't clobber each other's in-progress temp file (the
/// rename itself is still the single atomic commit point); the file is removed
/// on a failed rename so a botched write leaves no stray temp behind.
fn write_atomic(path: &Path, contents: &[u8]) -> std::io::Result<()> {
    let tmp = tmp_sibling(path);
    std::fs::write(&tmp, contents)?;
    // `rename` replaces the destination on both POSIX and Windows (Rust's
    // `fs::rename` uses replace-existing semantics), so the swap is atomic.
    match std::fs::rename(&tmp, path) {
        Ok(()) => Ok(()),
        Err(e) => {
            let _ = std::fs::remove_file(&tmp);
            Err(e)
        }
    }
}

/// A sibling temp path for `path` (same directory, so the rename stays on one
/// filesystem), disambiguated by process id.
fn tmp_sibling(path: &Path) -> PathBuf {
    let mut name = path
        .file_name()
        .map(|n| n.to_os_string())
        .unwrap_or_else(|| std::ffi::OsString::from("phoenix.lock"));
    name.push(format!(".{}.tmp", std::process::id()));
    path.with_file_name(name)
}

/// Errors reading or interpreting a `phoenix.lock`.
#[derive(Debug)]
pub enum LockError {
    /// The lockfile could not be read from disk.
    Read(std::io::Error),
    /// The lockfile could not be written to disk.
    Write(std::io::Error),
    /// The lockfile contained invalid TOML.
    Parse(Box<toml::de::Error>),
    /// The lockfile's schema version is outside the range this toolchain
    /// understands (newer than [`LOCKFILE_VERSION`], or below the `1` floor —
    /// e.g. a missing/`0` version from a truncated or hand-written file).
    UnsupportedVersion(u32),
    /// `--locked` was requested but the manifest's resolved graph disagrees
    /// with the committed lockfile.
    Drift(Vec<String>),
}

impl std::fmt::Display for LockError {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        match self {
            LockError::Read(e) => write!(f, "could not read phoenix.lock: {e}"),
            LockError::Write(e) => write!(f, "could not write phoenix.lock: {e}"),
            LockError::Parse(e) => write!(f, "invalid phoenix.lock: {e}"),
            LockError::UnsupportedVersion(v) => write!(
                f,
                "phoenix.lock is version {v}, but this Phoenix only understands \
                 version {LOCKFILE_VERSION}; upgrade Phoenix or delete the lockfile \
                 to regenerate it"
            ),
            LockError::Drift(diffs) => {
                write!(
                    f,
                    "phoenix.lock is out of date with phoenix.toml (run without --locked to update):"
                )?;
                for d in diffs {
                    write!(f, "\n  - {d}")?;
                }
                Ok(())
            }
        }
    }
}

impl std::error::Error for LockError {}

impl Lockfile {
    /// Build a lockfile from a resolved graph, recording only git-backed
    /// packages (path deps are never locked).
    pub fn from_graph(graph: &ResolvedGraph) -> Self {
        let mut packages = BTreeMap::new();
        for (name, pkg) in &graph.packages {
            // Source-kind is read from the explicit `source` discriminant, not
            // inferred from "has a rev": a git source is locked, a path source
            // is never recorded. (A future registry source would add an arm.)
            let PackageSource::Git { url, git_ref, rev } = &pkg.source else {
                continue;
            };
            let (tag, branch, rev_req) = match git_ref {
                GitRef::Tag(t) => (Some(t.clone()), None, None),
                GitRef::Branch(b) => (None, Some(b.clone()), None),
                // Lowercase the rev: object ids are case-insensitive hex, so
                // the canonical form keeps a pure-case re-pin out of `diff`.
                GitRef::Rev(r) => (None, None, Some(r.to_ascii_lowercase())),
                // Default-branch records no requested ref key; `rev` pins it.
                GitRef::DefaultBranch => (None, None, None),
            };
            packages.insert(
                name.clone(),
                LockedPackage::Git {
                    version: pkg.version.to_string(),
                    git: url.clone(),
                    tag,
                    branch,
                    rev_req,
                    rev: rev.clone(),
                },
            );
        }
        Lockfile {
            version: LOCKFILE_VERSION,
            packages,
        }
    }

    /// Read and parse a `phoenix.lock` from disk.
    pub fn read(path: &Path) -> Result<Self, LockError> {
        let contents = std::fs::read_to_string(path).map_err(LockError::Read)?;
        let lock: Lockfile =
            toml::from_str(&contents).map_err(|e| LockError::Parse(Box::new(e)))?;
        // Accept only versions in `1..=LOCKFILE_VERSION`. `version` has no serde
        // default (an absent key is already a parse error), but a hand-written
        // `version = 0` is a malformed lockfile, not a valid v0 we ever wrote —
        // reject it rather than treating it as current.
        if lock.version < 1 || lock.version > LOCKFILE_VERSION {
            return Err(LockError::UnsupportedVersion(lock.version));
        }
        Ok(lock)
    }

    /// Serialize to the canonical on-disk text (header comment + TOML body).
    pub fn to_toml_string(&self) -> String {
        // `toml::to_string` on a struct with a `version` field and a
        // `packages` map emits `version = N` followed by the name-keyed
        // `[packages.<name>]` tables — exactly the chosen format. The
        // serializer can't emit comments, so the header is prepended.
        let body = toml::to_string(self).expect("Lockfile serializes to TOML");
        format!("{LOCKFILE_HEADER}{body}")
    }

    /// Write the lockfile to `path` (overwriting any existing file), atomically.
    ///
    /// The contents are written to a sibling temp file and then renamed over
    /// `path`. A rename is atomic on the same filesystem (and the temp file is
    /// always a sibling, so it is), so an interrupted or failed write can never
    /// leave a half-written / truncated `phoenix.lock` behind — a later
    /// `--locked` read then always sees either the old lockfile or the complete
    /// new one, never a corrupt partial. (Inter-process races on the cache /
    /// lockfile are a separate, documented limitation.)
    pub fn write(&self, path: &Path) -> Result<(), LockError> {
        write_atomic(path, self.to_toml_string().as_bytes()).map_err(LockError::Write)
    }

    /// Compare this (freshly-resolved) lockfile against a committed one,
    /// returning a human-readable list of every difference. Empty ⇒ in sync.
    ///
    /// Used to implement `--locked`: the freshly-resolved graph is turned into
    /// a lockfile and diffed against what's committed.
    pub fn diff(&self, committed: &Lockfile) -> Vec<String> {
        let mut diffs = Vec::new();
        if self.version != committed.version {
            diffs.push(format!(
                "lockfile schema version changed: committed {} vs resolved {}",
                committed.version, self.version
            ));
        }
        for (name, fresh) in &self.packages {
            match committed.packages.get(name) {
                None => diffs.push(format!("`{name}` is missing from the lockfile")),
                Some(old) if old != fresh => diffs.push(describe_change(name, old, fresh)),
                Some(_) => {}
            }
        }
        for name in committed.packages.keys() {
            if !self.packages.contains_key(name) {
                diffs.push(format!("`{name}` is no longer a dependency"));
            }
        }
        diffs
    }
}

/// Describe how a locked package changed, for `--locked` drift diagnostics.
/// When the resolved commit moved, show the version/commit transition; when the
/// commit is unchanged but the source URL or *requested* ref differs, show that
/// change so the drift doesn't read as a confusing no-op.
fn describe_change(name: &str, old: &LockedPackage, fresh: &LockedPackage) -> String {
    // Both entries are git today; destructuring (rather than `git()` + an
    // empty-string fallback) keeps the URLs as plain `&str` and turns a future
    // non-git variant into a compile error that forces explicit handling here.
    let (LockedPackage::Git { git: old_git, .. }, LockedPackage::Git { git: fresh_git, .. }) =
        (old, fresh);
    if old.rev() != fresh.rev() {
        format!(
            "`{name}` changed: {} @ {} → {} @ {}",
            old.version(),
            short(old.rev()),
            fresh.version(),
            short(fresh.rev())
        )
    } else if old_git != fresh_git {
        // Same commit, different source: a pure ref-key diff would print an
        // identical-looking "ref changed: tag v1 → tag v1", so report the URL.
        format!("`{name}` source changed: {old_git} → {fresh_git}")
    } else {
        let old_ref = describe_locked_ref(old);
        let new_ref = describe_locked_ref(fresh);
        if old_ref != new_ref {
            format!("`{name}` ref changed: {old_ref} → {new_ref}")
        } else {
            // Same commit, source, and requested ref: nothing user-facing
            // actually differs, so don't print a confusing "X → X" no-op.
            format!("`{name}` changed")
        }
    }
}

/// Describe the *requested* ref a lock entry recorded.
fn describe_locked_ref(pkg: &LockedPackage) -> String {
    let LockedPackage::Git {
        tag,
        branch,
        rev_req,
        ..
    } = pkg;
    if let Some(t) = tag {
        format!("tag {t}")
    } else if let Some(b) = branch {
        format!("branch {b}")
    } else if let Some(r) = rev_req {
        format!("rev {r}")
    } else {
        "default branch".to_string()
    }
}

/// First 8 chars of a SHA for compact diagnostics. SHAs are ASCII hex, so this
/// byte slice always lands on a `char` boundary.
fn short(sha: &str) -> &str {
    &sha[..sha.len().min(8)]
}

/// Whether `haystack` begins with `prefix`, ignoring ASCII case. SHAs are ASCII
/// hex, so slicing `haystack` at `prefix.len()` always lands on a char boundary.
fn starts_with_ignore_ascii_case(haystack: &str, prefix: &str) -> bool {
    haystack.len() >= prefix.len()
        && haystack.as_bytes()[..prefix.len()].eq_ignore_ascii_case(prefix.as_bytes())
}

#[cfg(test)]
mod tests {
    use super::*;
    use crate::deps::graph::{PackageSource, ResolvedPackage};

    fn git_pkg(name: &str, version: &str, url: &str, rev: &str) -> ResolvedPackage {
        ResolvedPackage {
            name: name.to_string(),
            version: semver::Version::parse(version).unwrap(),
            root: std::path::PathBuf::from("/cache/x"),
            dependencies: BTreeMap::new(),
            source: PackageSource::Git {
                url: url.to_string(),
                git_ref: GitRef::Tag(format!("v{version}")),
                rev: rev.to_string(),
            },
        }
    }

    fn path_pkg(name: &str, version: &str) -> ResolvedPackage {
        ResolvedPackage {
            name: name.to_string(),
            version: semver::Version::parse(version).unwrap(),
            root: std::path::PathBuf::from("/proj/util"),
            dependencies: BTreeMap::new(),
            source: PackageSource::Path {
                path: std::path::PathBuf::from("/proj/util"),
            },
        }
    }

    fn graph_of(pkgs: Vec<ResolvedPackage>) -> ResolvedGraph {
        ResolvedGraph {
            packages: pkgs.into_iter().map(|p| (p.name.clone(), p)).collect(),
        }
    }

    #[test]
    fn from_graph_records_git_only() {
        let graph = graph_of(vec![
            git_pkg("http", "1.2.3", "u/http.git", "abc123def456"),
            path_pkg("util", "0.1.0"),
        ]);
        let lock = Lockfile::from_graph(&graph);
        assert_eq!(lock.packages.len(), 1, "path dep must be omitted");
        let http = &lock.packages["http"];
        assert_eq!(http.version(), "1.2.3");
        assert_eq!(http.git(), Some("u/http.git"));
        assert_eq!(http.rev(), "abc123def456");
    }

    #[test]
    fn round_trips_through_toml() {
        let graph = graph_of(vec![git_pkg("http", "1.2.3", "u/http.git", "abc123def456")]);
        let lock = Lockfile::from_graph(&graph);
        let text = lock.to_toml_string();
        assert!(text.starts_with("# Auto-generated by Phoenix"));
        assert!(text.contains("[packages.http]"));
        // The source-kind enum is `#[serde(untagged)]`, so the git entry must
        // serialize with NO discriminator field — byte-identical to the
        // pre-seam format. Pins the format-preservation guarantee.
        assert!(
            !text.contains("source ="),
            "untagged git entry must not emit a `source` discriminator: {text}"
        );
        // Parse the body back (skip the comment header — the TOML parser
        // tolerates leading comments, so the whole text parses).
        let parsed: Lockfile = toml::from_str(&text).unwrap();
        assert_eq!(parsed, lock);
    }

    #[test]
    fn write_is_atomic_and_leaves_no_temp_file() {
        // The atomic write overwrites an existing lockfile in place and leaves
        // no `.tmp` sibling behind — an interrupted write can never surface a
        // truncated `phoenix.lock` to a later `--locked` read.
        let tmp = tempfile::tempdir().unwrap();
        let path = tmp.path().join("phoenix.lock");

        let first = Lockfile::from_graph(&graph_of(vec![git_pkg(
            "http",
            "1.0.0",
            "u/http.git",
            "aaaa1111",
        )]));
        first.write(&path).unwrap();
        assert_eq!(
            std::fs::read_to_string(&path).unwrap(),
            first.to_toml_string()
        );

        // Overwriting works, and the result round-trips.
        let second = Lockfile::from_graph(&graph_of(vec![git_pkg(
            "http",
            "2.0.0",
            "u/http.git",
            "bbbb2222",
        )]));
        second.write(&path).unwrap();
        assert_eq!(
            Lockfile::read(&path).unwrap(),
            second,
            "overwrite must leave a complete, parseable lockfile"
        );

        // No stray temp file lingers in the directory.
        let strays: Vec<_> = std::fs::read_dir(tmp.path())
            .unwrap()
            .map(|e| e.unwrap().file_name().to_string_lossy().into_owned())
            .filter(|n| n.ends_with(".tmp"))
            .collect();
        assert!(strays.is_empty(), "temp files left behind: {strays:?}");
    }

    #[test]
    fn diff_detects_added_removed_and_changed() {
        let committed = Lockfile::from_graph(&graph_of(vec![git_pkg(
            "http",
            "1.0.0",
            "u/http.git",
            "aaaa1111",
        )]));
        // Fresh: http bumped to a new rev, and a new dep `io` added.
        let fresh = Lockfile::from_graph(&graph_of(vec![
            git_pkg("http", "1.1.0", "u/http.git", "bbbb2222"),
            git_pkg("io", "2.0.0", "u/io.git", "cccc3333"),
        ]));
        let diffs = fresh.diff(&committed);
        assert!(
            diffs
                .iter()
                .any(|d| d.contains("http") && d.contains("changed"))
        );
        assert!(
            diffs
                .iter()
                .any(|d| d.contains("io") && d.contains("missing"))
        );
    }

    #[test]
    fn diff_detects_dropped_dependency() {
        let committed = Lockfile::from_graph(&graph_of(vec![
            git_pkg("http", "1.0.0", "u/http.git", "aaaa1111"),
            git_pkg("io", "2.0.0", "u/io.git", "cccc3333"),
        ]));
        let fresh = Lockfile::from_graph(&graph_of(vec![git_pkg(
            "http",
            "1.0.0",
            "u/http.git",
            "aaaa1111",
        )]));
        let diffs = fresh.diff(&committed);
        assert_eq!(diffs.len(), 1);
        assert!(diffs[0].contains("io") && diffs[0].contains("no longer"));
    }

    #[test]
    fn diff_empty_when_in_sync() {
        let g = graph_of(vec![git_pkg("http", "1.0.0", "u/http.git", "aaaa1111")]);
        let a = Lockfile::from_graph(&g);
        let b = Lockfile::from_graph(&g);
        assert!(a.diff(&b).is_empty());
    }

    #[test]
    fn records_and_round_trips_requested_tag() {
        // A tag-pinned git dep records the `tag` ref alongside the resolved rev.
        let graph = graph_of(vec![git_pkg("http", "1.2.3", "u/http.git", "abc123def456")]);
        let lock = Lockfile::from_graph(&graph);
        assert_eq!(lock.packages["http"].tag(), Some("v1.2.3"));
        let text = lock.to_toml_string();
        assert!(text.contains("tag = \"v1.2.3\""), "{text}");
        let parsed: Lockfile = toml::from_str(&text).unwrap();
        assert_eq!(parsed, lock);
    }

    #[test]
    fn matches_ref_distinguishes_ref_changes() {
        let locked = LockedPackage::Git {
            version: "1.0.0".into(),
            git: "u/http.git".into(),
            tag: Some("v1.0.0".into()),
            branch: None,
            rev_req: None,
            rev: "abc123def456".into(),
        };
        // Same tag → reuse; bumped tag → re-resolve.
        assert!(locked.matches_ref(&GitRef::Tag("v1.0.0".into())));
        assert!(!locked.matches_ref(&GitRef::Tag("v1.1.0".into())));
        // A branch request never matches a tag-pinned entry.
        assert!(!locked.matches_ref(&GitRef::Branch("v1.0.0".into())));

        // A commit-pinned entry records `rev_req`.
        let by_rev = LockedPackage::Git {
            version: "1.0.0".into(),
            git: "u/http.git".into(),
            tag: None,
            branch: None,
            rev_req: Some("abc123".into()),
            rev: "abc123def456".into(),
        };
        // Abbreviated rev matches the resolved commit; a different rev re-resolves.
        assert!(by_rev.matches_ref(&GitRef::Rev("abc123".into())));
        assert!(!by_rev.matches_ref(&GitRef::Rev("ffffff".into())));
        // Switching a commit pin to the default branch must re-resolve, not
        // silently reuse the pinned commit.
        assert!(!by_rev.matches_ref(&GitRef::DefaultBranch));

        // A default-branch entry records no requested ref: it reuses the pinned
        // commit on a default-branch request, but a switch to a rev pin re-resolves.
        let by_default = LockedPackage::Git {
            version: "1.0.0".into(),
            git: "u/http.git".into(),
            tag: None,
            branch: None,
            rev_req: None,
            rev: "abc123def456".into(),
        };
        assert!(by_default.matches_ref(&GitRef::DefaultBranch));
        assert!(!by_default.matches_ref(&GitRef::Rev("abc123".into())));
    }

    #[test]
    fn matches_ref_rev_is_case_insensitive_prefix() {
        // Resolved SHAs are lowercase hex; a manifest pinning an uppercase or
        // mixed-case abbreviated rev must still match the lock entry (a pure
        // case difference is not drift).
        let locked = LockedPackage::Git {
            version: "1.0.0".into(),
            git: "u/http.git".into(),
            tag: None,
            branch: None,
            rev_req: Some("ABC123".into()),
            rev: "abc123def456".into(),
        };
        assert!(locked.matches_ref(&GitRef::Rev("ABC123".into())));
        assert!(locked.matches_ref(&GitRef::Rev("aBc123".into())));
        assert!(locked.matches_ref(&GitRef::Rev("abc123".into())));
        // A genuinely different prefix still re-resolves.
        assert!(!locked.matches_ref(&GitRef::Rev("def456".into())));
        // A request longer than the resolved SHA can't be a prefix of it.
        assert!(!locked.matches_ref(&GitRef::Rev("abc123def4567890".into())));
    }

    #[test]
    fn records_requested_rev_to_distinguish_from_default_branch() {
        // An explicit `rev` pin records `rev_req`, so it is told apart from a
        // default-branch pin (which records none) and round-trips through TOML.
        let pkg = ResolvedPackage {
            name: "http".into(),
            version: semver::Version::parse("1.0.0").unwrap(),
            root: std::path::PathBuf::from("/cache/x"),
            dependencies: BTreeMap::new(),
            source: PackageSource::Git {
                url: "u/http.git".into(),
                git_ref: GitRef::Rev("abc123".into()),
                rev: "abc123def456".into(),
            },
        };
        let lock = Lockfile::from_graph(&graph_of(vec![pkg]));
        assert_eq!(lock.packages["http"].rev_req(), Some("abc123"));
        let parsed: Lockfile = toml::from_str(&lock.to_toml_string()).unwrap();
        assert_eq!(parsed, lock);
    }

    #[test]
    fn diff_flags_expanded_rev_abbreviation_as_ref_change() {
        // Expanding a `rev` pin's abbreviation (`abc123` → `abc123d`) while it
        // still resolves to the same commit is reported as ref drift: the
        // requested ref the manifest records changed, so a `--locked` build must
        // refuse rather than treat it as in sync. (This pins the intentional
        // behavior so a future refactor of `matches_ref`/`describe_change`
        // doesn't silently flip it.)
        let mk = |rev_req: &str| {
            let mut packages = BTreeMap::new();
            packages.insert(
                "http".to_string(),
                LockedPackage::Git {
                    version: "1.0.0".into(),
                    git: "u/http.git".into(),
                    tag: None,
                    branch: None,
                    rev_req: Some(rev_req.into()),
                    rev: "abc123def456".into(),
                },
            );
            Lockfile {
                version: LOCKFILE_VERSION,
                packages,
            }
        };
        let committed = mk("abc123");
        let fresh = mk("abc123d");
        let diffs = fresh.diff(&committed);
        assert_eq!(diffs.len(), 1, "{diffs:?}");
        assert!(
            diffs[0].contains("ref changed") && diffs[0].contains("abc123d"),
            "{diffs:?}"
        );
    }

    #[test]
    fn case_only_rev_change_is_not_drift() {
        // A `rev` pin that changes only in case (`ABC123` vs `abc123`) resolves
        // to the same commit and must NOT read as drift: `rev_req` is normalized
        // to lowercase on storage, matching `matches_ref`'s case-insensitive
        // compare, so a `--locked` build doesn't spuriously refuse a re-casing.
        let mk = |rev_req: &str| {
            let pkg = ResolvedPackage {
                name: "http".into(),
                version: semver::Version::parse("1.0.0").unwrap(),
                root: std::path::PathBuf::from("/cache/x"),
                dependencies: BTreeMap::new(),
                source: PackageSource::Git {
                    url: "u/http.git".into(),
                    git_ref: GitRef::Rev(rev_req.into()),
                    rev: "abc123def456".into(),
                },
            };
            Lockfile::from_graph(&graph_of(vec![pkg]))
        };
        let committed = mk("ABC123");
        let fresh = mk("abc123");
        assert_eq!(
            committed.packages["http"].rev_req(),
            Some("abc123"),
            "rev_req must be stored lowercased"
        );
        assert!(
            fresh.diff(&committed).is_empty(),
            "a pure case change in a rev pin must not be drift: {:?}",
            fresh.diff(&committed)
        );
    }

    #[test]
    fn rejects_future_version() {
        let text = "version = 999\n";
        let dir = tempfile::tempdir().unwrap();
        let path = dir.path().join("phoenix.lock");
        std::fs::write(&path, text).unwrap();
        assert!(matches!(
            Lockfile::read(&path),
            Err(LockError::UnsupportedVersion(999))
        ));
    }

    #[test]
    fn rejects_malformed_toml() {
        // A lockfile that isn't valid TOML surfaces as a `Parse` error (not a
        // panic or a silent default), so a corrupt/truncated file is reported
        // clearly rather than misread.
        let dir = tempfile::tempdir().unwrap();
        let path = dir.path().join("phoenix.lock");
        std::fs::write(&path, "this is = = not valid toml\n").unwrap();
        assert!(matches!(Lockfile::read(&path), Err(LockError::Parse(_))));
    }

    #[test]
    fn rejects_zero_version() {
        // A `version = 0` lockfile is malformed (we never wrote a v0); it must be
        // rejected rather than silently accepted as if current.
        let dir = tempfile::tempdir().unwrap();
        let path = dir.path().join("phoenix.lock");
        std::fs::write(&path, "version = 0\n").unwrap();
        assert!(matches!(
            Lockfile::read(&path),
            Err(LockError::UnsupportedVersion(0))
        ));
    }
}
